4	// compliance with the License.  You may obtain a copy of the License at
5	// http://solderpad.org/licenses/SHL-0.51. Unless required by applicable law
6	// or agreed to in writing, software, hardware and materials distributed under
7	// this License is distributed on an "AS IS" BASIS, WITHOUT WARRANTIES OR
8	// CONDITIONS OF ANY KIND, either express or implied. See the License for the
9	// specific language governing permissions and limitations under the License.
10	//
11	// Authors:
12	// - Florian Zaruba <zarubaf@iis.ee.ethz.ch>
13	// - Wolfgang Roenninger <wroennin@iis.ee.ethz.ch>
14	
15	// `axi_xbar_monitor` implements an AXI bus monitor that is tuned for the AXI crossbar.
16	// It snoops on each of the slaves and master ports of the crossbar and
17	// populates FIFOs and ID queues to validate that no AXI beats get
18	// lost or sent to the wrong destination.
19	
20	package tb_axi_xbar_pkg;
21	  class axi_xbar_monitor #(
22	    parameter int unsigned AxiAddrWidth,
23	    parameter int unsigned AxiDataWidth,
24	    parameter int unsigned AxiIdWidthMasters,
25	    parameter int unsigned AxiIdWidthSlaves,
26	    parameter int unsigned AxiUserWidth,
27	    parameter int unsigned NoMasters,
28	    parameter int unsigned NoSlaves,
29	    parameter int unsigned NoAddrRules,
30	    parameter type         rule_t,
31	    parameter rule_t [NoAddrRules-1:0] AddrMap,
32	      // Stimuli application and test time
33	    parameter time  TimeTest
34	  );
35	    typedef logic [AxiIdWidthMasters-1:0] mst_axi_id_t;
36	    typedef logic [AxiIdWidthSlaves-1:0]  slv_axi_id_t;
37	    typedef logic [AxiAddrWidth-1:0]      axi_addr_t;
38	
39	    typedef logic [$clog2(NoMasters)-1:0] idx_mst_t;
40	    typedef int unsigned                  idx_slv_t; // from rule_t
41	
42	    typedef struct packed {
43	      mst_axi_id_t mst_axi_id;
44	      logic        last;
45	    } master_exp_t;
46	    typedef struct packed {
47	      slv_axi_id_t   slv_axi_id;
48	      axi_addr_t     slv_axi_addr;
49	      axi_pkg::len_t slv_axi_len;
50	    } exp_ax_t;
51	    typedef struct packed {
52	      slv_axi_id_t slv_axi_id;
53	      logic        last;
54	    } slave_exp_t;
55	
56	    typedef rand_id_queue_pkg::rand_id_queue #(
57	      .data_t   ( master_exp_t      ),
58	      .ID_WIDTH ( AxiIdWidthMasters )
59	    ) master_exp_queue_t;
60	    typedef rand_id_queue_pkg::rand_id_queue #(
61	      .data_t   ( exp_ax_t         ),
62	      .ID_WIDTH ( AxiIdWidthSlaves )
63	    ) ax_queue_t;
64	
65	    typedef rand_id_queue_pkg::rand_id_queue #(
66	      .data_t   ( slave_exp_t      ),
67	      .ID_WIDTH ( AxiIdWidthSlaves )
68	    ) slave_exp_queue_t;
69	
70	    //-----------------------------------------
71	    // Monitoring virtual interfaces
72	    //-----------------------------------------
73	    virtual AXI_BUS_DV #(
74	      .AXI_ADDR_WIDTH ( AxiAddrWidth      ),
75	      .AXI_DATA_WIDTH ( AxiDataWidth      ),
76	      .AXI_ID_WIDTH   ( AxiIdWidthMasters ),
77	      .AXI_USER_WIDTH ( AxiUserWidth      )
78	    ) masters_axi [NoMasters-1:0];
79	    virtual AXI_BUS_DV #(
80	      .AXI_ADDR_WIDTH ( AxiAddrWidth      ),
81	      .AXI_DATA_WIDTH ( AxiDataWidth      ),
82	      .AXI_ID_WIDTH   ( AxiIdWidthSlaves  ),
83	      .AXI_USER_WIDTH ( AxiUserWidth      )
84	    ) slaves_axi [NoSlaves-1:0];
85	    //-----------------------------------------
86	    // Queues and FIFOs to hold the expected ids
87	    //-----------------------------------------
88	    // Write transactions
89	    ax_queue_t         exp_aw_queue [NoSlaves-1:0];
90	    slave_exp_t        exp_w_fifo   [NoSlaves-1:0][$];
91	    slave_exp_t        act_w_fifo   [NoSlaves-1:0][$];
92	    master_exp_queue_t exp_b_queue  [NoMasters-1:0];
93	
94	    // Read transactions
95	    ax_queue_t            exp_ar_queue  [NoSlaves-1:0];
96	    master_exp_queue_t    exp_r_queue  [NoMasters-1:0];
97	
98	    //-----------------------------------------
99	    // Bookkeeping
100	    //-----------------------------------------
101	    longint unsigned tests_expected;
102	    longint unsigned tests_conducted;
103	    longint unsigned tests_failed;
104	    std::semaphore   cnt_sem;
105	
106	    //-----------------------------------------
107	    // Constructor
108	    //-----------------------------------------
109	    function new(
110	      virtual AXI_BUS_DV #(
111	        .AXI_ADDR_WIDTH ( AxiAddrWidth      ),
112	        .AXI_DATA_WIDTH ( AxiDataWidth      ),
113	        .AXI_ID_WIDTH   ( AxiIdWidthMasters ),
114	        .AXI_USER_WIDTH ( AxiUserWidth      )
115	      ) axi_masters_vif [NoMasters-1:0],
116	      virtual AXI_BUS_DV #(
117	        .AXI_ADDR_WIDTH ( AxiAddrWidth      ),
118	        .AXI_DATA_WIDTH ( AxiDataWidth      ),
119	        .AXI_ID_WIDTH   ( AxiIdWidthSlaves  ),
120	        .AXI_USER_WIDTH ( AxiUserWidth      )
121	      ) axi_slaves_vif [NoSlaves-1:0]
122	    );
123	      begin
124	        this.masters_axi     = axi_masters_vif;
125	        this.slaves_axi      = axi_slaves_vif;
126	        this.tests_expected  = 0;
127	        this.tests_conducted = 0;
128	        this.tests_failed    = 0;
129	        for (int unsigned i = 0; i < NoMasters; i++) begin
130	          this.exp_b_queue[i] = new;
131	          this.exp_r_queue[i] = new;
132	        end
133	        for (int unsigned i = 0; i < NoSlaves; i++) begin
134	          this.exp_aw_queue[i] = new;
135	          this.exp_ar_queue[i] = new;
136	        end
137	        this.cnt_sem = new(1);
138	      end
139	    endfunction
140	
141	    // when start the testing
142	    task cycle_start;
143	      #TimeTest;
144	    endtask
145	
146	    // when is cycle finished
147	    task cycle_end;
148	      @(posedge masters_axi[0].clk_i);
149	    endtask
150	
151	    // This task monitors a slave ports of the crossbar. Every time an AW beat is seen
152	    // it populates an id queue at the right master port (if there is no expected decode error),
153	    // populates the expected b response in its own id_queue and in case when the atomic bit [5]
154	    // is set it also injects an expected response in the R channel.
155	    task automatic monitor_mst_aw(input int unsigned i);
156	      idx_slv_t    to_slave_idx;
157	      exp_ax_t     exp_aw;
158	      slv_axi_id_t exp_aw_id;
159	      bit          decerr;
160	
161	      master_exp_t exp_b;
162	
163	      if (masters_axi[i].aw_valid && masters_axi[i].aw_ready) begin
164	        // check if it should go to a decerror
165	        decerr = 1'b1;
166	        for (int unsigned j = 0; j < NoAddrRules; j++) begin
167	          if ((masters_axi[i].aw_addr >= AddrMap[j].start_addr) &&
168	              (masters_axi[i].aw_addr < AddrMap[j].end_addr)) begin
169	            to_slave_idx = idx_slv_t'(AddrMap[j].idx);
170	            decerr = 1'b0;
171	          end
172	        end
173	        // send the exp aw beat down into the queue of the slave when no decerror
174	        if (!decerr) begin
175	          exp_aw_id = {idx_mst_t'(i), masters_axi[i].aw_id};
176	          // $display("Test exp aw_id: %b",exp_aw_id);
177	          exp_aw = '{slv_axi_id:   exp_aw_id,
178	                     slv_axi_addr: masters_axi[i].aw_addr,
179	                     slv_axi_len:  masters_axi[i].aw_len   };
180	          this.exp_aw_queue[to_slave_idx].push(exp_aw_id, exp_aw);
181	          incr_expected_tests(3);
182	          $display("%0tns > Master %0d: AW to Slave %0d: Axi ID: %b",
183	              $time, i, to_slave_idx, masters_axi[i].aw_id);
184	        end else begin
185	          $display("%0tns > Master %0d: AW to Decerror: Axi ID: %b",
186	              $time, i, to_slave_idx, masters_axi[i].aw_id);
187	        end
188	        // populate the expected b queue anyway
189	        exp_b = '{mst_axi_id: masters_axi[i].aw_id, last: 1'b1};
190	        this.exp_b_queue[i].push(masters_axi[i].aw_id, exp_b);
191	        incr_expected_tests(1);
192	        $display("        Expect B response.");
193	        // inject expected r beats on this id, if it is an atop
194	        if(masters_axi[i].aw_atop[5]) begin
195	          // push the required r beats into the right fifo (reuse the exp_b variable)
196	          $display("        Expect R response, len: %0d.", masters_axi[i].aw_len);
197	          for (int unsigned j = 0; j <= masters_axi[i].aw_len; j++) begin
198	            exp_b = (j == masters_axi[i].aw_len) ?
199	                '{mst_axi_id: masters_axi[i].aw_id, last: 1'b1} :
200	                '{mst_axi_id: masters_axi[i].aw_id, last: 1'b0};
201	            this.exp_r_queue[i].push(masters_axi[i].aw_id, exp_b);
202	            incr_expected_tests(1);
203	          end
204	        end
205	      end
206	    endtask : monitor_mst_aw
207	
208	    // This task monitors a slave port of the crossbar. Every time there is an AW vector it
209	    // gets checked for its contents and if it was expected. The task then pushes an expected
210	    // amount of W beats in the respective fifo. Emphasis of the last flag.
211	    task automatic monitor_slv_aw(input int unsigned i);
212	      exp_ax_t    exp_aw;
213	      slave_exp_t exp_slv_w;
214	      //  $display("%0t > Was triggered: aw_valid %b, aw_ready: %b",
215	      //       $time(), slaves_axi[i].aw_valid, slaves_axi[i].aw_ready);
216	      if (slaves_axi[i].aw_valid && slaves_axi[i].aw_ready) begin
217	        // test if the aw beat was expected
218	        exp_aw = this.exp_aw_queue[i].pop_id(slaves_axi[i].aw_id);
219	        $display("%0tns > Slave  %0d: AW Axi ID: %b",
220	            $time, i, slaves_axi[i].aw_id);
221	        if (exp_aw.slv_axi_id != slaves_axi[i].aw_id) begin
222	          incr_failed_tests(1);
223	          $warning("Slave %0d: Unexpected AW with ID: %b", i, slaves_axi[i].aw_id);
224	        end
225	        if (exp_aw.slv_axi_addr != slaves_axi[i].aw_addr) begin
226	          incr_failed_tests(1);
227	          $warning("Slave %0d: Unexpected AW with ID: %b and ADDR: %h, exp: %h",
228	              i, slaves_axi[i].aw_id, slaves_axi[i].aw_addr, exp_aw.slv_axi_addr);
229	        end
230	        if (exp_aw.slv_axi_len != slaves_axi[i].aw_len) begin
231	          incr_failed_tests(1);
232	          $warning("Slave %0d: Unexpected AW with ID: %b and LEN: %h, exp: %h",
233	              i, slaves_axi[i].aw_id, slaves_axi[i].aw_len, exp_aw.slv_axi_len);
234	        end
235	        incr_conducted_tests(3);
236	
237	        // push the required w beats into the right fifo
238	        incr_expected_tests(slaves_axi[i].aw_len + 1);
239	        for (int unsigned j = 0; j <= slaves_axi[i].aw_len; j++) begin
240	          exp_slv_w = (j == slaves_axi[i].aw_len) ?
241	              '{slv_axi_id: slaves_axi[i].aw_id, last: 1'b1} :
242	              '{slv_axi_id: slaves_axi[i].aw_id, last: 1'b0};
243	          this.exp_w_fifo[i].push_back(exp_slv_w);
244	        end
245	      end
246	    endtask : monitor_slv_aw
247	
248	    // This task just pushes every W beat that gets sent on a master port in its respective fifo.
249	    task automatic monitor_slv_w(input int unsigned i);
250	      slave_exp_t     act_slv_w;
251	      if (slaves_axi[i].w_valid && slaves_axi[i].w_ready) begin
252	        // $display("%0t > W beat on Slave %0d, last flag: %b", $time, i, slaves_axi[i].w_last);
253	        act_slv_w = '{last: slaves_axi[i].w_last , default:'0};
254	        this.act_w_fifo[i].push_back(act_slv_w);
255	      end
256	    endtask : monitor_slv_w
257	
258	    // This task compares the expected and actual W beats on a master port. The reason that
259	    // this is not done in `monitor_slv_w` is that there can be per protocol W beats on the
260	    // channel, before AW is sent to the slave.
261	    task automatic check_slv_w(input int unsigned i);
262	      slave_exp_t exp_w, act_w;
263	      while (this.exp_w_fifo[i].size() != 0 && this.act_w_fifo[i].size() != 0) begin
264	
265	        exp_w = this.exp_w_fifo[i].pop_front();
266	        act_w = this.act_w_fifo[i].pop_front();
267	        // do the check
268	        incr_conducted_tests(1);
269	        if(exp_w.last != act_w.last) begin
270	          incr_failed_tests(1);
271	          $warning("Slave %d: unexpected W beat last flag %b, expected: %b.",
272	                 i, act_w.last, exp_w.last);
273	        end
274	      end
275	    endtask : check_slv_w
276	
277	    // This task checks if a B response is allowed on a slave port of the crossbar.
278	    task automatic monitor_mst_b(input int unsigned i);
279	      master_exp_t exp_b;
280	      mst_axi_id_t axi_b_id;
281	      if (masters_axi[i].b_valid && masters_axi[i].b_ready) begin
282	        incr_conducted_tests(1);
283	        axi_b_id = masters_axi[i].b_id;
284	        $display("%0tns > Master %0d: Got last B with id: %b",
285	                $time, i, axi_b_id);
286	        if (this.exp_b_queue[i].is_empty()) begin
287	          incr_failed_tests(1);
288	          $warning("Master %d: unexpected B beat with ID: %b detected!", i, axi_b_id);
289	        end else begin
290	          exp_b = this.exp_b_queue[i].pop_id(axi_b_id);
291	          if (axi_b_id != exp_b.mst_axi_id) begin
292	            incr_failed_tests(1);
293	            $warning("Master: %d got unexpected B with ID: %b", i, axi_b_id);
294	          end
295	        end
296	      end
297	    endtask : monitor_mst_b
298	
299	    // This task monitors the AR channel of a slave port of the crossbar. For each AR it populates
300	    // the corresponding ID queue with the number of r beats indicated on the `ar_len` field.
301	    // Emphasis on the last flag. We will detect reordering, if the last flags do not match,
302	    // as each `random` burst tend to have a different length.
303	    task automatic monitor_mst_ar(input int unsigned i);
304	      mst_axi_id_t   mst_axi_id;
305	      axi_addr_t     mst_axi_addr;
306	      axi_pkg::len_t mst_axi_len;
307	
308	      idx_slv_t      exp_slv_idx;
309	      slv_axi_id_t   exp_slv_axi_id;
310	      exp_ax_t       exp_slv_ar;
311	      master_exp_t   exp_mst_r;
312	
313	      logic          exp_decerr;
314	
315	      if (masters_axi[i].ar_valid && masters_axi[i].ar_ready) begin
316	        exp_decerr     = 1'b1;
317	        mst_axi_id     = masters_axi[i].ar_id;
318	        mst_axi_addr   = masters_axi[i].ar_addr;
319	        mst_axi_len    = masters_axi[i].ar_len;
320	        exp_slv_axi_id = {idx_mst_t'(i), mst_axi_id};
321	        exp_slv_idx    = '0;
322	        for (int unsigned j = 0; j < NoAddrRules; j++) begin
323	          if ((mst_axi_addr >= AddrMap[j].start_addr) && (mst_axi_addr < AddrMap[j].end_addr)) begin
324	            exp_slv_idx = AddrMap[j].idx;
325	            exp_decerr  = 1'b0;
326	          end
327	        end
328	        if (exp_decerr) begin
329	          $display("%0tns > Master %0d: AR to Decerror: Axi ID: %b",
330	              $time, i, mst_axi_id);
331	        end else begin
332	          $display("%0tns > Master %0d: AR to Slave %0d: Axi ID: %b",
333	              $time, i, exp_slv_idx, mst_axi_id);
334	          // push the expected vectors AW for exp_slv
335	          exp_slv_ar = '{slv_axi_id:    exp_slv_axi_id,
336	                         slv_axi_addr:  mst_axi_addr,
337	                         slv_axi_len:   mst_axi_len     };
338	          //$display("Expected Slv Axi Id is: %b", exp_slv_axi_id);
339	          this.exp_ar_queue[exp_slv_idx].push(exp_slv_axi_id, exp_slv_ar);
340	          incr_expected_tests(1);
341	        end
342	        // push the required r beats into the right fifo
343	          $display("        Expect R response, len: %0d.", masters_axi[i].ar_len);
344	          for (int unsigned j = 0; j <= mst_axi_len; j++) begin
345	          exp_mst_r = (j == mst_axi_len) ? '{mst_axi_id: mst_axi_id, last: 1'b1} :
346	                                           '{mst_axi_id: mst_axi_id, last: 1'b0};
347	          this.exp_r_queue[i].push(mst_axi_id, exp_mst_r);
348	          incr_expected_tests(1);
349	        end
350	      end
351	    endtask : monitor_mst_ar
352	
353	    // This task monitors a master port of the crossbar and checks if a transmitted AR beat was
354	    // expected.
355	    task automatic monitor_slv_ar(input int unsigned i);
356	      exp_ax_t       exp_slv_ar;
357	      slv_axi_id_t   slv_axi_id;
358	      if (slaves_axi[i].ar_valid && slaves_axi[i].ar_ready) begin
359	        incr_conducted_tests(1);
360	        slv_axi_id = slaves_axi[i].ar_id;
361	        if (this.exp_ar_queue[i].is_empty()) begin
362	          incr_failed_tests(1);
363	        end else begin
364	          // check that the ids are the same
365	          exp_slv_ar = this.exp_ar_queue[i].pop_id(slv_axi_id);
366	          $display("%0tns > Slave  %0d: AR Axi ID: %b", $time, i, slv_axi_id);
367	          if (exp_slv_ar.slv_axi_id != slv_axi_id) begin
368	            incr_failed_tests(1);
369	            $warning("Slave  %d: Unexpected AR with ID: %b", i, slv_axi_id);
370	          end
371	        end
372	      end
373	    endtask : monitor_slv_ar
374	
375	    // This task does the R channel monitoring on a slave port. It compares the last flags,
376	    // which are determined by the sequence of previously sent AR vectors.
377	    task automatic monitor_mst_r(input int unsigned i);
378	      master_exp_t exp_mst_r;
379	      mst_axi_id_t mst_axi_r_id;
380	      logic        mst_axi_r_last;
381	      if (masters_axi[i].r_valid && masters_axi[i].r_ready) begin
382	        incr_conducted_tests(1);
383	        mst_axi_r_id   = masters_axi[i].r_id;
384	        mst_axi_r_last = masters_axi[i].r_last;
385	        if (mst_axi_r_last) begin
386	          $display("%0tns > Master %0d: Got last R with id: %b",
387	                   $time, i, mst_axi_r_id);
388	        end
389	        if (this.exp_r_queue[i].is_empty()) begin
390	          incr_failed_tests(1);
391	          $warning("Master %d: unexpected R beat with ID: %b detected!", i, mst_axi_r_id);
392	        end else begin
393	          exp_mst_r = this.exp_r_queue[i].pop_id(mst_axi_r_id);
394	          if (mst_axi_r_id != exp_mst_r.mst_axi_id) begin
395	            incr_failed_tests(1);
396	            $warning("Master: %d got unexpected R with ID: %b", i, mst_axi_r_id);
397	          end
398	          if (mst_axi_r_last != exp_mst_r.last) begin
399	            incr_failed_tests(1);
400	            $warning("Master: %d got unexpected R with ID: %b and last flag: %b",
401	                i, mst_axi_r_id, mst_axi_r_last);
402	          end
403	        end
404	      end
405	    endtask : monitor_mst_r
406	
407	    // Some tasks to manage bookkeeping of the tests conducted.
408	    task incr_expected_tests(input int unsigned times);
409	      cnt_sem.get();
410	      this.tests_expected += times;
411	      cnt_sem.put();
412	    endtask : incr_expected_tests
413	
414	    task incr_conducted_tests(input int unsigned times);
415	      cnt_sem.get();
416	      this.tests_conducted += times;
417	      cnt_sem.put();
418	    endtask : incr_conducted_tests
419	
420	    task incr_failed_tests(input int unsigned times);
421	      cnt_sem.get();
422	      this.tests_failed += times;
423	      cnt_sem.put();
424	    endtask : incr_failed_tests
425	
426	    // This task invokes the various monitoring tasks. It first forks in two, spitting
427	    // the tasks that should continuously run and the ones that get invoked every clock cycle.
428	    // For the tasks every clock cycle all processes that only push something in the fifo's and
429	    // Queues get run. When they are finished the processes that pop something get run.
430	    task run();
431	      Continous: fork
432	        begin
433	          do begin
434	            cycle_start();
435	            // at every cycle span some monitoring processes
436	            // execute all processes that put something into the queues
437	            PushMon: fork
438	              proc_mst_aw: begin
439	                for (int unsigned i = 0; i < NoMasters; i++) begin
440	                  monitor_mst_aw(i);
441	                end
442	              end
443	              proc_mst_ar: begin
444	                for (int unsigned i = 0; i < NoMasters; i++) begin
445	                  monitor_mst_ar(i);
446	                end
447	              end
448	            join : PushMon
449	            // this one pops and pushes something
450	            proc_slv_aw: begin
451	              for (int unsigned i = 0; i < NoSlaves; i++) begin
452	                monitor_slv_aw(i);
453	              end
454	            end
455	            proc_slv_w: begin
456	              for (int unsigned i = 0; i < NoSlaves; i++) begin
457	                monitor_slv_w(i);
458	              end
459	            end
460	            // These only pop somethong from the queses
461	            PopMon: fork
462	              proc_mst_b: begin
463	                for (int unsigned i = 0; i < NoMasters; i++) begin
464	                  monitor_mst_b(i);
465	                end
466	              end
467	              proc_slv_ar: begin
468	                for (int unsigned i = 0; i < NoSlaves; i++) begin
469	                  monitor_slv_ar(i);
470	                end
471	              end
472	              proc_mst_r: begin
473	                for (int unsigned i = 0; i < NoMasters; i++) begin
474	                  monitor_mst_r(i);
475	                end
476	              end
477	            join : PopMon
478	            // check the slave W fifos last
479	            proc_check_slv_w: begin
480	              for (int unsigned i = 0; i < NoSlaves; i++) begin
481	                check_slv_w(i);
482	              end
483	            end
484	            cycle_end();
485	          end while (1'b1);
486	        end
487	      join
488	    endtask : run
489	
490	    task print_result();
491	      $info("Simulation has ended!");
492	      $display("Tests Expected:  %d", this.tests_expected);
493	      $display("Tests Conducted: %d", this.tests_conducted);
494	      $display("Tests Failed:    %d", this.tests_failed);
495	      if(tests_failed > 0) begin
496	        $error("Simulation encountered unexpected Transactions!!!!!!");
497	      end
498	      if(tests_conducted == 0) begin
499	        $error("Simulation did not conduct any tests!");
500	      end
501	    endtask : print_result
502	  endclass : axi_xbar_monitor
503	endpackage
504

